<template>
    <div class="Index" layout="row top-spread">
        <div self="left">
            <router-link to="/" style="font-size:50px">PersonalInformation</router-link>
        </div>
        <div self="right">
            <router-link to="/home" style="font-size:30px">Home</router-link>
        </div>
        <div self="right">
            <router-link to="/about" style="font-size:30px">About</router-link>
        </div>
        <div self="right">
            <router-link to="/blogs" style="font-size:30px">Blogs</router-link>
        </div>
        <div self="right">
            <router-link to="/products" style="font-size:30px">Products</router-link>
        </div>
    </div>
    <div class="slideshow">
        <div class="slides" ref="slides">
            <div class="slide" v-for="slide in slides" :key="slide.id">
                <img :src="`./background/${slide.filename}`" :alt="slide.description"/>
            </div>
        </div>
    </div>
</template>

<script>
import "flex-layout-attribute/css/flex-layout-attribute.css";

export default {
    data() {
        return {
            images: [
                {url: 'background_img/preview1.jpg'},
                {url: 'background_img/preview2.jpg'},
            ],
            current: 0,
            timer: null,
        };
    },
    mounted() {
        this.timer = setInterval(this.currentSlide, 3000);
    },
    methods: {
        currentSlide() {
            let slides = this.$refs.slides.querySelectorAll(".slide");
            for (let i = 0; i < slides.length; i++) {
                slides[i].style.display = "none";
            }
            this.current++;
            if (this.current > slides.length) {
                this.current = 1;
            }
            slides[this.current - 1].style.display = "block";
        },
    },
    beforeUnmount() {
        clearInterval(this.timer);
    },
};
</script>

<style scoped>
.slideshow {
    width: 100%;
    height: 100%;
    position: absolute;
    top: 0;
    left: 0;
    z-index: -1;
}

.slides {
    width: 100%;
    height: 100%;
}

.slide {
    display: none;
    width: 100%;
    height: 100%;
    position: absolute;
    top: 0;
    left: 0;
}

</style>
